Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var sut = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await sut.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.NotFound);
        var sut = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await sut.FetchAsync("https://example.com"));
    }

    [TestMethod]
    [Timeout(3000)]
    public async Task FetchAsync_RespectsTimeout()
    {
        // Handler that delays longer than the test timeout
        var handler = new FakeHandler("slow", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(30));
        var sut = new DataFetcher(new HttpClient(handler));

        // TestContext.CancellationToken fires when [Timeout] expires,
        // which cancels GetAsync inside FetchAsync
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await sut.FetchAsync("https://example.com",
                _testContext.CancellationToken));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsBeforeCompleting()
    {
        var handler = new FakeHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(30));
        var sut = new DataFetcher(new HttpClient(handler));

        using var cts = new CancellationTokenSource();
        cts.Cancel(); // cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await sut.FetchAsync("https://example.com", cts.Token));
    }

    // Reusable fake handler — no mocking library needed
    private sealed class FakeHandler(
        string content, HttpStatusCode status, TimeSpan delay = default)
        : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
                await Task.Delay(delay, cancellationToken);

            return new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `TestContext` via constructor | Enables `readonly` field, satisfies nullability |
| `[Timeout]` + `_testContext.CancellationToken` | Cooperative timeout — the token fires when the timeout expires, cancelling the real async call |
| `Assert.ThrowsExactlyAsync<T>` | Verifies the exact exception type (not `[ExpectedException]`) |
| `FakeHandler` instead of mocking `HttpClient` | `HttpClient` can't be mocked directly; subclassing `HttpMessageHandler` is the standard approach |
| `sealed` test class | Performance and design clarity |

The critical insight: **`[Timeout]` alone won't kill a hung async call**. You must pass `TestContext.CancellationToken` into the method under test so the timeout can actually cancel the underlying operation.
